new file mode 100644
index 0000000..fdf8e93
--- /dev/null
+++ b/src/controllers/well-known.js
@@ -0,0 +1,50 @@
+'use strict';
+
+const nconf = require('nconf');
+const user = require('../user');
+
+const wellKnownController = module.exports;
+
+wellKnownController.changePassword = function (req, res) {
+	res.redirect(`${nconf.get('relative_path')}/me/edit/password`);
+};
+
+wellKnownController.webfinger = async function (req, res) {
+	const { resource } = req.query;
+	if (!resource) {
+		return res.status(400).json({ error: 'bad_request' });
+	}
+
+	const resourceMatch = resource.match(/^acct:([^@]+)@(.+)$/);
+	if (!resourceMatch) {
+		return res.status(400).json({ error: 'bad_request' });
+	}
+
+	const [, username, domain] = resourceMatch;
+	const url = nconf.get('url');
+	const urlObj = new URL(url);
+
+	if (domain !== urlObj.hostname) {
+		return res.status(404).json({ error: 'not_found' });
+	}
+
+	const uid = await user.getUidByUsername(username);
+	if (!uid) {
+		return res.status(404).json({ error: 'not_found' });
+	}
+
+	const userslug = await user.getUserField(uid, 'userslug');
+	const profileUrl = `${url}/user/${userslug}`;
+
+	res.type('application/jrd+json').json({
+		subject: resource,
+		aliases: [profileUrl],
+		links: [
+			{
+				rel: 'http://webfinger.net/rel/profile-page',
+				type: 'text/html',
+				href: profileUrl,
+			},
+		],
+	});
+};
